import Header from '../components/Header';
import Navbar from '../components/Navbar';


import React, { useState } from 'react';

const BGPLLaMaPage = () => {
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState(null);

  // Example existing queries, in a real app these would be fetched from an API
  const existingQueries = [
    'Perform BGP analysis using PyBGPStream ...',
    'Provide the definition of BGP',
    // ... other queries
  ];

  const handleQueryChange = (e) => {
    setQuery(e.target.value);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    // Here you would send the query to your backend API
    // For now, we'll just simulate a response
    const simulatedResponse = 'Simulated response for: ' + query;
    setResponse(simulatedResponse);
  };

  return (
    <div className="container mx-auto p-4">
        <Header />
        <Navbar />
        <div className="flex justify-between">
            {/* Existing Queries Section */}
            <div className="w-1/3">
            <h2 className="font-bold mb-2">Existing Queries</h2>
            <ul className="border p-2">
                {existingQueries.map((query, index) => (
                <li key={index} className="mb-1">
                    {query}
                </li>
                ))}
            </ul>
            </div>

            {/* Query Input Section */}
            <div className="w-2/3 ml-4">
            <h2 className="font-bold mb-2">Welcome to BGP-LLaMA on Django</h2>
            <p className="mb-4">Enter your query in the text box below.</p>
            <form onSubmit={handleSubmit}>
                <div className="mb-4">
                <label htmlFor="queryInput" className="block mb-2">Input</label>
                <textarea
                    id="queryInput"
                    rows="4"
                    className="w-full border p-2"
                    placeholder="Enter your query here"
                    value={query}
                    onChange={handleQueryChange}
                />
                </div>
                <button
                type="submit"
                className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
                >
                Submit
                </button>
            </form>

            {/* Model Output Section */}
            {response && (
                <div className="mt-4">
                <h3 className="font-bold mb-2">Your query:</h3>
                <div className="border p-2">
                    {response}
                </div>
                </div>
            )}
            </div>
        </div>
    </div>
  );
};

export default BGPLLaMaPage;
